// // This module compares two 4-bit numbers and outputs if the first is greater than or equal to the second
module top_module (
    input [3:0] a,
    input [3:0] b,
    output lt,
    output eq,
    output gt
);

    assign lt = a < b;
    assign eq = a == b;
    assign gt = a > b;

endmodule
